import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

import { addRow } from '../../consts/crud';
import { handleLogout } from '../../consts/handleLogout';
import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function AddSing() {
    const [name, setName] = useState('');
    const [login, setLogin] = useState('');
    const [password, setPassword] = useState('');
    const [privilege_id, setPrivilegeID] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const submitSing = async (e) => {
        setLoading(true);

        e.preventDefault();
        const headers = {
            'Content-Type': 'multipart/form-data',
            'Accept': 'application/json'
        };
        const user = { name, login, password, privilege_id };
        addRow('/users', user, headers);
        setName('');
        setLogin('');
        setPassword('');
        setPrivilegeID('');
        navigate('/users');

        setLoading(false);
    };

    return (
        <div>
            <nav className='navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0'>
                <div className='container-fluid py-2'>
                    <Link className='navbar-brand fs-3 fw-bold' to='/main'>Дорожное хозяйство</Link>
                    <div class='btn-group'>
                        <button type='button' class='btn btn-info'>{ localStorage.getItem('login') }</button>
                        <button type='button' class='btn btn-info dropdown-toggle dropdown-toggle-split' data-bs-toggle='dropdown' aria-expanded='false'>
                            <span class='visually-hidden'>Переключатель выпадающего списка</span>
                        </button>
                        <ul class='dropdown-menu'>
                            <li>
                                <a class='dropdown-item'>
                                    <button
                                        onClick={() => { handleLogout(localStorage.getItem('id')); navigate('/login') }} 
                                        className='dropdown-item'
                                        disabled={loading}
                                    >
                                        {loading ? (
                                            <>
                                                <span className='spinner'></span>
                                                Выход...
                                            </>
                                        ) : 'Выйти'}
                                    </button>
                                </a>
                            </li>
                        </ul>
                    </div>
                </div>
            </nav>
            <form className='container' onSubmit={submitSing}>
                <h1>Создание дорожного знака</h1>
                <div className='mb-3'>
                    <lable className='form-label'>ФИО</lable>
                    <input 
                        type='text'
                        name='name' 
                        value={name.name} 
                        onChange={(e) => setName(e.target.value)}
                        className='form-input'  
                        placeholder='name'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Логин</lable>
                    <input 
                        type='text'
                        name='login' 
                        value={login.login} 
                        onChange={(e) => setLogin(e.target.value)}
                        className='form-input'  
                        placeholder='login'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Пароль</lable>
                    <input 
                        type='password'
                        name='password' 
                        value={password.password} 
                        onChange={(e) => setPassword(e.target.value)}
                        className='form-input'  
                        placeholder='password'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>Индификатор привелегии</lable>
                    <input 
                        type='text'
                        name='privilege_id' 
                        value={privilege_id.privilege_id} 
                        onChange={(e) => setPrivilegeID(e.target.value)}
                        className='form-input'  
                        placeholder='privilege_id'
                        required  
                    />
                </div>
                <button 
                    type='submit' 
                    className='btn btn-primary'
                >
                    Добавить
                </button>
                <button 
                    type='submit' 
                    className='btn btn-danger' 
                    onClick={() => navigate('/users')}
                >
                    Назад
                </button>
            </form>
        </div>
    )

};

export default AddSing;
